using System.Diagnostics;
using Microsoft.Extensions.Logging;

namespace RagKit.Internal;

/// <summary>
/// Observability backbone: one <see cref="ActivitySource"/> for tracing and
/// helpers to create <see cref="ILogger"/> instances from the factory stored in
/// <see cref="RagOptions"/>. Every internal component — LLM client, guardrail,
/// classifier, router, chunker, lexical index — gets its logger from here so the
/// consumer controls verbosity and sinks via the standard
/// <c>Microsoft.Extensions.Logging</c> infrastructure.
/// </summary>
internal static class Telemetry
{
    /// <summary>The source for all RagKit tracing spans. Consumers add an
    /// <c>ActivityListener</c> (or use OpenTelemetry) to see these.</summary>
    public static readonly ActivitySource Source = new("RagKit");

    /// <summary>
    /// Create a logger for the given type, respecting the factory set in options.
    /// Returns a <c>NullLogger</c> when no factory is configured (the default).
    /// Called once per component during <see cref="RagClient"/> construction.
    /// </summary>
    public static ILogger<T> GetLogger<T>(RagOptions options) =>
        (options.LoggerFactory ?? Microsoft.Extensions.Logging.Abstractions.NullLoggerFactory.Instance)
            .CreateLogger<T>();
}

