            var newlyStarted = new List<string>();
            try
            {
                using var doc = JsonDocument.Parse(data);
                var choices = doc.RootElement.GetProperty("choices");
                if (choices.GetArrayLength() == 0 || !choices[0].TryGetProperty("delta", out var delta))
